import { Link } from 'react-router-dom';
function LeadTable({ leads, onEdit, onDelete }) {
  if (!leads || leads.length === 0) {
    return <p className="empty-msg">No leads found.</p>;
  }

  return (
    <div className="table-wrapper">
      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>Country</th>
            <th>Course</th>
            <th>Status</th>
            <th>Priority</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {leads.map((lead) => (
            <tr key={lead._id}>
              <td>
  <Link to={`/leads/${lead._id}`}>
    {lead.fullName}
  </Link>
</td>
              <td>{lead.country}</td>
              <td>{lead.courseInterested}</td>
              <td>
                <span className={`badge badge-${lead.leadStatus?.replace(/\s+/g, '-').toLowerCase()}`}>
                  {lead.leadStatus}
                </span>
              </td>
              <td>{lead.priority}</td>
              <td className="actions">
                <button className="btn-edit" onClick={() => onEdit(lead)}>Edit</button>
                <button className="btn-delete" onClick={() => onDelete(lead._id)}>Delete</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default LeadTable;
